def replaceWords(dictionary, sentence):
    dictionary = sorted(dictionary, key=len)
    def shortest_root(word):
        for root in dictionary:
            if word.startswith(root):
                return root
        return word
    return " ".join(shortest_root(w) for w in sentence.split())

